{
  "parameters": "z.object({
  partnerName: z.string().describe("The name of the partner bot to coordinate with"),
  radius: z.number().default(1).describe("How close to the calculated midpoint to get")
})",
  "executionArgs": {
    "partnerName": "Bot2",
    "radius": 1
  },
  "code": "const partner = bot.players[args.partnerName]?.entity;
if (!partner) {
  return "<ERROR>: Cannot find player " + args.partnerName + " in range to calculate a gathering point.";
}

const myPos = bot.entity.position;
const partnerPos = partner.position;
const gatherX = (myPos.x + partnerPos.x) / 2;
const gatherY = (myPos.y + partnerPos.y) / 2;
const gatherZ = (myPos.z + partnerPos.z) / 2;
const gatheringPoint = new Vec3(gatherX, gatherY, gatherZ);

startBackgroundSkill(bot, 'move_to_gathering_point', async function (token) {
  const movements = new Movements(bot);
  bot.pathfinder.setMovements(movements);

  const goal = new goals.GoalNear(gatheringPoint.x, gatheringPoint.y, gatheringPoint.z, args.radius);

  try {
    await bot.pathfinder.goto(goal);
    if (!token.cancelled) {
      console.log('Arrived at gathering point between bot and ' + args.partnerName);
    }
  } catch (err) {
    if (!token.cancelled) {
      console.error('Failed to reach gathering point:', err);
    }
  }
});

return "<MOVING>: Calculating midpoint between self and " + args.partnerName + " at (" + gatherX.toFixed(1) + ", " + gatherY.toFixed(1) + ", " + gatherZ.toFixed(1) + ") and moving there.";"
}

{
  "parameters": "z.object({
  "target_id": z.number().optional().describe("The entity ID to attack. If not provided, the nearest hostile entity will be targeted."),
  "preferredDistance": z.number().default(15).describe("The ideal distance to maintain from the target while shooting."),
  "weapon": z.string().default("bow").describe("The name of the weapon to use, typically 'bow'.")
})",
  "executionArgs": {
    "target_id": 17,
    "preferredDistance": 15,
    "weapon": "bow"
  },
  "code": "const findItem = function (bot, name) {
  return bot.inventory.items().find(function (item) {
    return item.name === name || (item.displayName && item.displayName.toLowerCase().includes(name));
  });
};

const bow = findItem(bot, args.weapon);
const arrows = findItem(bot, 'arrow');

if (!bow) {
  return "<ERROR>: No " + args.weapon + " found in inventory.";
}

if (!arrows) {
  return "<ERROR>: No arrows found in inventory.";
}

let targetEntity = null;
if (args.target_id) {
  targetEntity = bot.entities[args.target_id];
} else {
  targetEntity = bot.nearestEntity(function (e) {
    return (e.type === 'hostile' || e.type === 'mob') && e.health > 0;
  });
}

if (!targetEntity) {
  return "<CANCELLED>: No hostile target found nearby.";
}

const sleep = function (ms) { return new Promise(function (resolve) { setTimeout(resolve, ms); }); };

startBackgroundSkill(bot, 'ranged_attack_nearest_hostile', async function (token) {
  const movements = new Movements(bot);
  const checkStatus = function () {
    return !token.cancelled && bot.health > 0 && bot.entity && targetEntity && targetEntity.isValid && (targetEntity.health === undefined || targetEntity.health > 0);
  };

  while (checkStatus()) {
    if (!bot.physicsEnabled) {
      await sleep(100);
      continue;
    }

    const currentBow = findItem(bot, args.weapon);
    const currentArrows = findItem(bot, 'arrow');
    if (!currentBow || !currentArrows) break;

    await bot.equip(currentBow, 'hand');

    const dist = bot.entity.position.distanceTo(targetEntity.position);

    // Positioning logic: Maintain preferred distance
    if (dist > args.preferredDistance + 2 || dist < args.preferredDistance - 2) {
      bot.pathfinder.setMovements(movements);
      // GoalFollow tries to stay within a range. 
      // If we are too close, we use GoalAway if we find a custom implementation, 
      // otherwise we use follow with a range.
      bot.pathfinder.setGoal(new goals.GoalFollow(targetEntity, args.preferredDistance), true);
    } else {
      bot.pathfinder.setGoal(null);
    }

    // Attack logic: Charge, Aim, Fire
    bot.activateItem(); // Start drawing the bow
    const chargeStart = Date.now();

    // Wait for charge while tracking the target visually
    while (Date.now() - chargeStart < 1200 && checkStatus()) {
      // Aim slightly above center for gravity
      const aimPos = targetEntity.position.offset(0, targetEntity.height * 0.8, 0);
      await bot.lookAt(aimPos, true);
      await sleep(50);
    }

    if (checkStatus()) {
      bot.deactivateItem(); // Release the arrow
      await sleep(200); // Cooldown/reset
    }
  }

  bot.pathfinder.setGoal(null);
});

return "<RANGED_ATTACK>: Starting bow attack on " + (targetEntity.name || "target") + " while maintaining distance of " + args.preferredDistance + ".";"
}

{
  "parameters": "z.object({ amount: z.number().int().positive().describe("The number of bread pieces to consume") })",
  "executionArgs": { "amount": 3 },
  "code": "const maxFood = 20;
const consumeMs = 1700;
const freezePollMs = 50;
const sleep = function (ms) {
  return new Promise(function (resolve) { setTimeout(resolve, ms); });
};
const findBread = function () {
  return bot.inventory.items().find(function (item) { return item.name === 'bread'; });
};

if ((bot.food || 0) >= maxFood) {
  return "<ALREADY FULL>: Hunger is already full at " + bot.food + ".";
}

const item = findBread();
if (!item) {
  return "<NO BREAD>: Cannot eat because there is no bread in inventory.";
}

startBackgroundSkill(bot, 'eat_bread', async function (token) {
  const canContinue = function () { return !token.cancelled && bot.health > 0 && Boolean(bot.entity); };
  const waitUntilWorldActive = async function () {
    while (!bot.physicsEnabled) {
      if (!canContinue()) { return false; }
      await sleep(freezePollMs);
    }
    return canContinue();
  };

  let eatenCount = 0;
  while (canContinue() && (bot.food || 0) < maxFood && eatenCount < args.amount) {
    const bread = findBread();
    if (!bread) {
       console.log('Ran out of bread after eating ' + eatenCount);
       break;
    }

    try {
      await bot.equip(bread, 'hand');
      if (!await waitUntilWorldActive()) { return; }
      bot.activateItem();
      await sleep(consumeMs);
      bot.deactivateItem();
      eatenCount++;
      // Small delay between items
      await sleep(200);
    } catch (err) {
      console.error('Failure during eating loop:', err);
      break;
    }
  }
});

return "<EATING>: Started eating up to " + args.amount + " bread (Current food: " + bot.food + ").";"
}

{
  "parameters": "z.object({
  weapon: z.string().describe("The item name to use for attacking, e.g., 'stone_sword'"),
  range: z.number().describe("The maximum distance to search for a hostile mob")
})",
  "executionArgs": {
    "weapon": "stone_sword",
    "range": 3.5
  },
  "code": "const weaponName = args.weapon.trim().toLowerCase();
const reach = args.range;

if (bot.health <= 0) {
  return "<FAILED>: Bot is dead and cannot attack.";
}

const findWeapon = function () {
  return bot.inventory.items().find(function (item) {
    return item.name.includes(weaponName) || (item.displayName && item.displayName.toLowerCase().includes(weaponName));
  });
};

const weaponItem = findWeapon();
if (!weaponItem) {
  return "<NO_WEAPON>: Could not find any item matching '" + weaponName + "' in inventory.";
}

try {
  await bot.equip(weaponItem, 'hand');
} catch (err) {
  return "<EQUIP_ERROR>: Failed to equip " + weaponName + ": " + err.message;
}

const target = bot.nearestEntity(function (entity) {
  if (entity.type !== 'mob' && entity.type !== 'hostile') return false;
  const isFriendly = ['villager', 'iron_golem', 'passive'].some(name => entity.name.includes(name));
  if (isFriendly) return false;
  const dist = bot.entity.position.distanceTo(entity.position);
  return dist <= reach;
});

if (!target) {
  return "<NO_TARGET>: No hostile mobs found within " + reach + " blocks.";
}

startBackgroundSkill(bot, 'melee_attack_hostile', async function (token) {
  const attackInterval = 600; 
  const canContinue = function () {
    return !token.cancelled && 
           bot.health > 0 && 
           Boolean(bot.entity) && 
           target && 
           target.isValid && 
           (target.health === undefined || target.health > 0);
  };

  while (canContinue()) {
    if (!bot.physicsEnabled) {
      await new Promise(function (resolve) { setTimeout(resolve, 50); });
      continue;
    }

    const dist = bot.entity.position.distanceTo(target.position);
    if (dist > reach + 1) {
      break; 
    }

    // Aim at the head/upper body
    const eyePos = target.position.offset(0, target.height || 1.6, 0);
    await bot.lookAt(eyePos, true);

    bot.attack(target);

    await new Promise(function (resolve) { setTimeout(resolve, attackInterval); });
  }
});

return "<ATTACKING>: Now engaging " + target.name + " at distance " + bot.entity.position.distanceTo(target.position).toFixed(1) + ".";"
}
